module.render:
const gap = args.gap || '1.5rem';
const valigns = { top: 'flex-start', center: 'center', stretch: 'stretch' };
const valign = valigns[String(args.valign || 'stretch').toLowerCase()] || 'stretch';
const aligns = { left: 'left', center: 'center', right: 'right' };
const align = aligns[String(args.align || 'left').toLowerCase()] || 'left';
const divided = String(args.divider) === 'true';
const items = sections.filter(function (s) { return s.trim().length > 0; });
const count = parseInt(args.count, 10) || items.length || 2;
const basis = (100 / count);
const cls = 'mdp-mod-columns' + (divided ? ' mdp-cols-divided' : '');
let html = `\n\n<div class="${cls}" style="gap: ${gap}; align-items: ${valign}; text-align: ${align};">\n`;
items.forEach(function (section) {
  const contentStr = section.trim();
  html += `<div class="mdp-mod-columns-col" style="flex: 0 0 calc(${basis}% - ${gap}); max-width: calc(${basis}% - ${gap});">\n\n${contentStr}\n\n</div>`;
});
html += `</div>\n\n`;
return html;
